import matchms; import requests; import json; from rdkit import Chem; from rdkit.Chem import Descriptors; import sys; spectra = matchms.importing.load_from_msp('{inputs.0}'); annotated = []; changelog = []; for spec in spectra:
  if spec.get('compound_name') and not spec.get('smiles'):
    try:
      resp = requests.get(f'https://pubchem.ncbi.nlm.nih.gov/rest/pug/compound/name/{spec["compound_name"]}/JSON').json()
      if 'PC_Compounds' in resp and len(resp['PC_Compounds']) > 0:
        compound = resp['PC_Compounds'][0]
        smiles = next((p['value']['sval'] for p in compound.get('props', []) if p.get('urn', {}).get('label') == 'SMILES'), None)
        inchi = next((p['value']['sval'] for p in compound.get('props', []) if p.get('urn', {}).get('label') == 'InChI'), None)
        inchi_key = next((p['value']['sval'] for p in compound.get('props', []) if p.get('urn', {}).get('label') == 'InChIKey'), None)
        if smiles:
          mol = Chem.MolFromSmiles(smiles); mono_mass = Descriptors.MolWt(mol)
          parent_mass = float(spec.get('parent_mass', -1))
          if abs(mono_mass - parent_mass) < 0.01:
            spec.set('smiles', smiles); spec.set('inchi', inchi); spec.set('inchi_key', inchi_key)
            annotated.append(spec)
            changelog.append({'compound_name': spec['compound_name'], 'smiles': smiles, 'inchi': inchi, 'inchi_key': inchi_key, 'parent_mass': parent_mass, 'monoisotopic_mass': mono_mass, 'status': 'PASS'})
          else:
            changelog.append({'compound_name': spec['compound_name'], 'status': 'MASS_MISMATCH', 'parent_mass': parent_mass, 'monoisotopic_mass': mono_mass})
    except Exception as e:
      changelog.append({'compound_name': spec.get('compound_name'), 'status': 'ERROR', 'error': str(e)})
if annotated:
  matchms.exporting.save_as_msp(annotated, 'annotated_spectra.msp')
with open('changelog.json', 'w') as f:
  json.dump(changelog, f, indent=2)
